## 4. Core Services Architecture

### 4.1 Authentication Service

```typescript
// auth.service.ts
import { Injectable } from '@nestjs/common';
import * as jwt from 'jsonwebtoken';
import * as bcrypt from 'bcrypt';

@Injectable()
export class AuthService {
  constructor(private readonly usersRepository: UsersRepository) {}

  async register(email: string, password: string) {
    const hashedPassword = await bcrypt.hash(password, 10);

    const user = await this.usersRepository.create({
      email,
      password_hash: hashedPassword,
    });

    return this.generateTokens(user.id);
  }

  async login(email: string, password: string) {
    const user = await this.usersRepository.findByEmail(email);

    if (!user) {
      throw new UnauthorizedException('Invalid credentials');
    }

    const isPasswordValid = await bcrypt.compare(
      password,
      user.password_hash
    );

    if (!isPasswordValid) {
      throw new UnauthorizedException('Invalid credentials');
    }

    return this.generateTokens(user.id);
  }

  private generateTokens(userId: string) {
    const accessToken = jwt.sign(
      { sub: userId, type: 'access' },
      process.env.JWT_SECRET,
      { expiresIn: '15m' }
    );

    const refreshToken = jwt.sign(
      { sub: userId, type: 'refresh' },
      process.env.JWT_REFRESH_SECRET,
      { expiresIn: '7d' }
    );

    return { accessToken, refreshToken };
  }

  async validateToken(token: string) {
    return jwt.verify(token, process.env.JWT_SECRET);
  }
}
```

### 4.2 Contact Management Service

```typescript
// contacts.service.ts
import { Injectable } from '@nestjs/common';
import { ContactRepository } from './contact.repository';
import { ElasticsearchService } from '@nestjs/elasticsearch';
import { RabbitMQService } from '../shared/rabbitmq.service';

@Injectable()
export class ContactsService {
  constructor(
    private readonly contactRepository: ContactRepository,
    private readonly elasticsearchService: ElasticsearchService,
    private readonly rabbitmqService: RabbitMQService,
    private readonly cacheService: CacheService,
  ) {}

  async createContact(userId: string, contactData: CreateContactDto) {
    // Create contact
    const contact = await this.contactRepository.create({
      ...contactData,
      user_id: userId,
    });

    // Index in Elasticsearch
    await this.elasticsearchService.index({
      index: 'contacts',
      id: contact.id,
      body: this.mapContactToDocument(contact),
    });

    // Clear user's contact cache
    await this.cacheService.del(`user:${userId}:contacts`);

    // Publish event
    await this.rabbitmqService.publish('contact.created', {
      userId,
      contactId: contact.id,
      timestamp: new Date(),
    });

    return contact;
  }

  async updateContact(
    userId: string,
    contactId: string,
    updates: UpdateContactDto,
  ) {
    const oldContact = await this.contactRepository.findById(contactId);

    if (!oldContact || oldContact.user_id !== userId) {
      throw new ForbiddenException('Not authorized');
    }

    const updatedContact = await this.contactRepository.update(
      contactId,
      updates,
    );

    // Update search index
    await this.elasticsearchService.update({
      index: 'contacts',
      id: contactId,
      body: { doc: this.mapContactToDocument(updatedContact) },
    });

    // Record history
    await this.recordContactHistory(userId, contactId, 'UPDATE', oldContact, updatedContact);

    // Publish event
    await this.rabbitmqService.publish('contact.updated', {
      userId,
      contactId,
      changes: updates,
    });

    return updatedContact;
  }

  async deleteContact(userId: string, contactId: string) {
    const contact = await this.contactRepository.findById(contactId);

    if (!contact || contact.user_id !== userId) {
      throw new ForbiddenException('Not authorized');
    }

    // Soft delete
    await this.contactRepository.softDelete(contactId);

    // Remove from search index
    await this.elasticsearchService.delete({
      index: 'contacts',
      id: contactId,
    });

    // Record history
    await this.recordContactHistory(userId, contactId, 'DELETE', contact, null);

    // Publish event
    await this.rabbitmqService.publish('contact.deleted', {
      userId,
      contactId,
    });
  }

  async searchContacts(userId: string, query: string, filters?: SearchFilters) {
    const searchBody = {
      query: {
        bool: {
          must: [
            { term: { user_id: userId } },
            {
              multi_match: {
                query,
                fields: ['first_name', 'last_name', 'email', 'phone', 'company'],
                fuzziness: 'AUTO',
              },
            },
          ],
          filter: this.buildFilters(filters),
        },
      },
      size: filters?.limit || 20,
      from: (filters?.page || 0) * (filters?.limit || 20),
    };

    const results = await this.elasticsearchService.search({
      index: 'contacts',
      body: searchBody,
    });

    return results.body.hits.hits.map((hit: any) => hit._source);
  }

  async getContacts(userId: string, pagination: PaginationDto) {
    // Try cache first
    const cacheKey = `user:${userId}:contacts:${pagination.page}`;
    const cached = await this.cacheService.get(cacheKey);

    if (cached) {
      return JSON.parse(cached);
    }

    // Database query
    const contacts = await this.contactRepository.findByUserId(
      userId,
      pagination,
    );

    // Cache for 5 minutes
    await this.cacheService.set(cacheKey, JSON.stringify(contacts), 300);

    return contacts;
  }

  private mapContactToDocument(contact: Contact) {
    return {
      id: contact.id,
      user_id: contact.user_id,
      first_name: contact.first_name,
      last_name: contact.last_name,
      email: contact.email,
      phone: contact.phone,
      company: contact.company,
      job_title: contact.job_title,
      full_text: `${contact.first_name} ${contact.last_name} ${contact.email} ${contact.phone}`,
    };
  }

  private async recordContactHistory(
    userId: string,
    contactId: string,
    action: 'CREATE' | 'UPDATE' | 'DELETE',
    oldValues: any,
    newValues: any,
  ) {
    await this.contactRepository.recordHistory({
      contact_id: contactId,
      user_id: userId,
      action,
      old_values: action !== 'CREATE' ? oldValues : null,
      new_values: action !== 'DELETE' ? newValues : null,
    });
  }

  private buildFilters(filters?: SearchFilters) {
    const filterArray = [];

    if (filters?.company) {
      filterArray.push({ term: { company: filters.company } });
    }

    if (filters?.is_favorite) {
      filterArray.push({ term: { is_favorite: true } });
    }

    return filterArray;
  }
}
```

### 4.3 Sync Service (for offline-first mobile)

```typescript
// sync.service.ts
import { Injectable } from '@nestjs/common';
import { ContactRepository } from './contact.repository';
import { SyncTokenRepository } from './sync-token.repository';

@Injectable()
export class SyncService {
  constructor(
    private readonly contactRepository: ContactRepository,
    private readonly syncTokenRepository: SyncTokenRepository,
  ) {}

  async getSyncChanges(userId: string, deviceId: string, lastSyncToken?: string) {
    const syncRecord = await this.syncTokenRepository.findByUserAndDevice(
      userId,
      deviceId,
    );

    const lastSync = syncRecord?.last_sync || new Date(0);

    // Get all changes since last sync
    const changes = await this.contactRepository.getChangesSince(
      userId,
      lastSync,
    );

    // Generate new sync token
    const newSyncToken = this.generateSyncToken();

    // Update sync record
    await this.syncTokenRepository.update(userId, deviceId, {
      last_sync: new Date(),
      sync_token: newSyncToken,
    });

    return {
      syncToken: newSyncToken,
      changes: {
        created: changes.filter(c => c.action === 'CREATE'),
        updated: changes.filter(c => c.action === 'UPDATE'),
        deleted: changes.filter(c => c.action === 'DELETE'),
      },
    };
  }

  async applyLocalChanges(
    userId: string,
    deviceId: string,
    localChanges: LocalChanges,
  ) {
    const conflicts = [];

    for (const contact of localChanges.created || []) {
      try {
        await this.contactRepository.create({ ...contact, user_id: userId });
      } catch (error) {
        conflicts.push({ contact, error: error.message });
      }
    }

    for (const contact of localChanges.updated || []) {
      try {
        // Check for conflicts
        const serverContact = await this.contactRepository.findById(contact.id);

        if (serverContact.updated_at > contact.updated_at) {
          conflicts.push({
            contact,
            serverVersion: serverContact,
            reason: 'Server version is newer',
          });
        } else {
          await this.contactRepository.update(contact.id, contact);
        }
      } catch (error) {
        conflicts.push({ contact, error: error.message });
      }
    }

    for (const contactId of localChanges.deleted || []) {
      try {
        await this.contactRepository.softDelete(contactId);
      } catch (error) {
        conflicts.push({ contactId, error: error.message });
      }
    }

    return { conflicts };
  }

  private generateSyncToken(): string {
    return Buffer.from(`${Date.now()}-${Math.random()}`).toString('base64');
  }
}
