export const ContactManager: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedContacts, setSelectedContacts] = useState<Set<string>>(new Set());
  const [openDialog, setOpenDialog] = useState(false);
  const [editingContact, setEditingContact] = useState<Contact | null>(null);
  const [filters, setFilters] = useState({ isFavorite: false, company: '' });

  // Fetch contacts
  const { data: contacts, isLoading, refetch } = useQuery(
    ['contacts', { searchQuery, filters }],
    () => {
      if (searchQuery.length > 2) {
        return contactApi.search(searchQuery, filters);
      }
      return contactApi.getAll();
    },
    {
      debounceTime: 300,
    },
  );

  // Create mutation
  const createMutation = useMutation(contactApi.create, {
    onSuccess: () => {
      refetch();
      setOpenDialog(false);
    },
  });

  // Update mutation
  const updateMutation = useMutation(
    ({ id, data }: { id: string; data: UpdateContactDto }) =>
      contactApi.update(id, data),
    {
      onSuccess: () => {
        refetch();
        setOpenDialog(false);
        setEditingContact(null);
      },
    },
  );

  // Delete mutation
  const deleteMutation = useMutation(contactApi.delete, {
    onSuccess: () => {
      refetch();
      setSelectedContacts(new Set());
    },
  });

  // Bulk delete
  const bulkDeleteMutation = useMutation(
    (ids: string[]) => contactApi.bulkDelete(ids),
    {
      onSuccess: () => {
        refetch();
        setSelectedContacts(new Set());
      },
    },
  );

  const handleSubmit = useCallback(
    (formData: CreateContactDto) => {
      if (editingContact) {
        updateMutation.mutate({
          id: editingContact.id,
          data: formData,
        });
      } else {
        createMutation.mutate(formData);
      }
    },
    [editingContact, createMutation, updateMutation],
  );

  const handleBulkDelete = useCallback(() => {
    if (selectedContacts.size > 0) {
      bulkDeleteMutation.mutate(Array.from(selectedContacts));
    }
  }, [selectedContacts, bulkDeleteMutation]);

  const toggleSelectContact = useCallback((contactId: string) => {
    setSelectedContacts((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(contactId)) {
        newSet.delete(contactId);
      } else {
        newSet.add(contactId);
      }
      return newSet;
    });
  }, []);

  return (
    <Box p={3}>
      <Box display="flex" gap={2} mb={3}>
        <TextField
          placeholder="Search contacts..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          fullWidth
        />
        <Button variant="contained" onClick={() => setOpenDialog(true)}>
          Add Contact
        </Button>
        {selectedContacts.size > 0 && (
          <Button
            variant="outlined"
            color="error"
            onClick={handleBulkDelete}
            disabled={bulkDeleteMutation.isLoading}
          >
            Delete ({selectedContacts.size})
          </Button>
        )}
      </Box>

      {/* Filters */}
      <Box display="flex" gap={2} mb={3}>
        <Chip
          label="Favorites"
          variant={filters.isFavorite ? 'filled' : 'outlined'}
          onClick={() =>
            setFilters((prev) => ({ ...prev, isFavorite: !prev.isFavorite }))
          }
        />
      </Box>

      {/* Table */}
      <Table>
        <TableHead>
          <TableRow>
            <TableCell padding="checkbox">
              <input
                type="checkbox"
                onChange={(e) => {
                  if (e.target.checked) {
                    setSelectedContacts(
                      new Set(contacts?.map((c: Contact) => c.id) || []),
                    );
                  } else {
                    setSelectedContacts(new Set());
                  }
                }}
                checked={
                  selectedContacts.size > 0 &&
                  selectedContacts.size === contacts?.length
                }
              />
            </TableCell>
            <TableCell>Name</TableCell>
            <TableCell>Email</TableCell>
            <TableCell>Phone</TableCell>
            <TableCell>Company</TableCell>
            <TableCell>Actions</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {isLoading ? (
            <TableRow>
              <TableCell colSpan={6}>Loading...</TableCell>
            </TableRow>
          ) : (
            contacts?.map((contact: Contact) => (
              <TableRow key={contact.id}>
                <TableCell padding="checkbox">
                  <input
                    type="checkbox"
                    checked={selectedContacts.has(contact.id)}
                    onChange={() => toggleSelectContact(contact.id)}
                  />
                </TableCell>
                <TableCell>{contact.first_name} {contact.last_name}</TableCell>
                <TableCell>{contact.email}</TableCell>
                <TableCell>{contact.phone}</TableCell>
                <TableCell>{contact.company}</TableCell>
                <TableCell>
                  <Button
                    size="small"
                    onClick={() => {
                      setEditingContact(contact);
                      setOpenDialog(true);
                    }}
                  >
                    Edit
                  </Button>
                  <Button
                    size="small"
                    color="error"
                    onClick={() => deleteMutation.mutate(contact.id)}
                  >
                    Delete
                  </Button>
                </TableCell>
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>

      {/* Contact Form Dialog */}
      <ContactFormDialog
        open={openDialog}
        onClose={() => {
          setOpenDialog(false);
          setEditingContact(null);
        }}
        onSubmit={handleSubmit}
        initialData={editingContact}
        isLoading={createMutation.isLoading || updateMutation.isLoading}
      />
    </Box>
  );
};
```

