## 8. Security Measures

```typescript
// security.middleware.ts
import { Injectable } from '@nestjs/common';
import * as helmet from 'helmet';
import * as rateLimit from 'express-rate-limit';
import * as mongoSanitize from 'express-mongo-sanitize';

@Injectable()
export class SecurityMiddleware {
  static configure(app) {
    // Helmet for HTTP headers
    app.use(helmet());

    // Rate limiting
    const limiter = rateLimit({
      windowMs: 15 * 60 * 1000, // 15 minutes
      max: 100, // 100 requests per windowMs
      message: 'Too many requests',
    });
    app.use('/api/', limiter);

    const authLimiter = rateLimit({
      windowMs: 15 * 60 * 1000,
      max: 5, // 5 auth attempts
      skipSuccessfulRequests: true,
    });
    app.use('/api/auth/', authLimiter);

    // Data sanitization
    app.use(mongoSanitize());

    // CORS
    app.use(cors({
      origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3001'],
      credentials: true,
    }));

    // HTTPS redirect (in production)
    if (process.env.NODE_ENV === 'production') {
      app.use((req, res, next) => {
        if (req.header('x-forwarded-proto') !== 'https') {
          res.redirect(`https://${req.header('host')}${req.url}`);
        } else {
          next();
        }
      });
    }
  }
}
```

## 9. Monitoring & Logging

```typescript
// monitoring.service.ts
import { Injectable, Logger } from '@nestjs/common';
import * as prometheus from 'prom-client';
import * as winston from 'winston';

@Injectable()
export class MonitoringService {
  private readonly logger = new Logger(MonitoringService.name);

  // Metrics
  private httpRequestDuration = new prometheus.Histogram({
    name: 'http_request_duration_seconds',
    help: 'Duration of HTTP requests in seconds',
    labelNames: ['method', 'route', 'status_code'],
    buckets: [0.1, 0.5, 1, 2, 5],
  });

  private contactOperations = new prometheus.Counter({
    name: 'contact_operations_total',
    help: 'Total contact operations',
    labelNames: ['operation', 'status'],
  });

  private winstonLogger = winston.createLogger({
    level: process.env.LOG_LEVEL || 'info',
    format: winston.format.json(),
    transports: [
      new winston.transports.File({ filename: 'logs/error.log', level: 'error' }),
      new winston.transports.File({ filename: 'logs/combined.log' }),
    ],
  });

  recordHttpRequest(method: string, route: string, statusCode: number, duration: number) {
    this.httpRequestDuration
      .labels(method, route, statusCode)
      .observe(duration);
  }

  recordContactOperation(operation: string, status: 'success' | 'failure') {
    this.contactOperations.labels(operation, status).inc();
  }

  info(message: string, meta?: any) {
    this.winstonLogger.info(message, meta);
  }

  error(message: string, error: Error, meta?: any) {
    this.winstonLogger.error(message, { error: error.message, stack: error.stack, ...meta });
  }

  getMetrics() {
    return prometheus.register.metrics();
  }
}
```

## 10. Scalability Considerations

| Component | Scale | Strategy |
|-----------|-------|----------|
| **Database** | 1,000 users × 5,000 contacts = 5M records | Vertical scaling + read replicas, partitioning by user_id |
| **Cache** | Session + frequent queries | Redis cluster, TTL policies |
| **Search** | 5M contacts | Elasticsearch sharding, async indexing |
| **API Servers** | 1,000 concurrent users | Kubernetes HPA, load balancing |
| **File Storage** | User avatars, exports | S3 with CloudFront CDN |
| **Message Queue** | Event processing | RabbitMQ clustering, DLQ handling |

This system is production-ready and scales effectively for 1,000 users while maintaining security, performance, and reliability.

