# Longest Increasing Subsequence in C++

Here's a comprehensive C++ function to find the longest increasing subsequence (LIS):

## Solution 1: Dynamic Programming Approach (O(n²))

```cpp
#include <vector>
#include <algorithm>

std::vector<int> longestIncreasingSubsequence(const std::vector<int>& arr) {
    int n = arr.size();
    if (n == 0) return {};

    // dp[i] = length of LIS ending at index i
    std::vector<int> dp(n, 1);
    // parent[i] = previous index in the LIS
    std::vector<int> parent(n, -1);

    // Fill dp array
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[j] < arr[i] && dp[j] + 1 > dp[i]) {
                dp[i] = dp[j] + 1;
                parent[i] = j;
            }
        }
    }

    // Find the index with maximum LIS length
    int maxLength = *std::max_element(dp.begin(), dp.end());
    int maxIndex = std::max_element(dp.begin(), dp.end()) - dp.begin();

    // Reconstruct the sequence
    std::vector<int> lis;
    int idx = maxIndex;
    while (idx != -1) {
        lis.push_back(arr[idx]);
        idx = parent[idx];
    }

    std::reverse(lis.begin(), lis.end());
    return lis;
}
```

## Solution 2: Binary Search Approach (O(n log n)) - More Efficient

```cpp
#include <vector>
#include <algorithm>

std::vector<int> longestIncreasingSubsequence(const std::vector<int>& arr) {
    int n = arr.size();
    if (n == 0) return {};

    // tails[i] = smallest tail element for LIS of length i+1
    std::vector<int> tails;
    // indices[i] = index in arr that tails[i] corresponds to
    std::vector<int> indices;
    // parent[i] = previous index in the LIS
    std::vector<int> parent(n, -1);

    for (int i = 0; i < n; i++) {
        // Find position to insert arr[i] in tails
        auto it = std::lower_bound(tails.begin(), tails.end(), arr[i]);
        int pos = it - tails.begin();

        // Store parent for reconstruction
        if (pos > 0) {
            parent[i] = indices[pos - 1];
        }

        if (pos == tails.size()) {
            tails.push_back(arr[i]);
            indices.push_back(i);
        } else {
            tails[pos] = arr[i];
            indices[pos] = i;
        }
    }

    // Reconstruct the sequence
    std::vector<int> lis;
    int idx = indices.back();
    while (idx != -1) {
        lis.push_back(arr[idx]);
        idx = parent[idx];
    }

    std::reverse(lis.begin(), lis.end());
    return lis;
}
```

## Usage Examples

```cpp
#include <iostream>

int main() {
    std::vector<int> arr = {10, 9, 2, 5, 3, 7, 101, 18};

    auto result = longestIncreasingSubsequence(arr);

    std::cout << "LIS: ";
    for (int num : result) {
        std::cout << num << " ";
    }
    std::cout << "\nLength: " << result.size() << std::endl;

    // Output:
    // LIS: 2 3 7 101 
    // Length: 4

    return 0;
}
```

## Comparison

| Approach | Time Complexity | Space Complexity | Notes |
|----------|-----------------|------------------|-------|
| DP (Solution 1) | O(n²) | O(n) | Simpler, suitable for small inputs |
| Binary Search (Solution 2) | O(n log n) | O(n) | **Recommended** - much faster for large inputs |

## Template Version (Works with any comparable type)

```cpp
