# Bogosort in C++

Here's an implementation of bogosort (also known as "stupid sort" or "random sort"), which randomly shuffles the array until it's sorted:

```cpp
#include <iostream>
#include <algorithm>
#include <cstdlib>
#include <ctime>
using namespace std;

// Function to check if array is sorted
bool isSorted(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        if (arr[i] > arr[i + 1]) {
            return false;
        }
    }
    return true;
}

// Function to print array
void printArray(int arr[], int n) {
    for (int i = 0; i < n; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
}

// Bogosort function
void bogoSort(int arr[], int n) {
    int iterations = 0;

    // Keep shuffling until sorted
    while (!isSorted(arr, n)) {
        // Shuffle the array
        random_shuffle(arr, arr + n);
        iterations++;

        // Optional: print progress
        if (iterations % 1000 == 0) {
            cout << "Iterations: " << iterations << endl;
        }
    }

    cout << "Total iterations: " << iterations << endl;
}

// Main function
int main() {
    srand(time(0));  // Seed random number generator

    int arr[] = {5, 2, 8, 1, 9};
    int n = sizeof(arr) / sizeof(arr[0]);

    cout << "Original array: ";
    printArray(arr, n);

    bogoSort(arr, n);

    cout << "Sorted array: ";
    printArray(arr, n);

    return 0;
}
