print("Sorted array:", bubble_sort(arr))
```

## 2. **Optimized Bubble Sort (Early Exit)**

```python
def bubble_sort_optimized(arr):
    """
    Optimized bubble sort with early exit
    Stops if array is already sorted
    """
    n = len(arr)

    for i in range(n):
        swapped = False

        # Traverse through unsorted portion
        for j in range(0, n - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
                swapped = True

        # If no swaps occurred, array is sorted
        if not swapped:
            break

    return arr


# Test
