def bubble_sort_generic(arr, reverse=False):
    """
    Bubble sort with custom sorting order
    """
    n = len(arr)

    for i in range(n):
        for j in range(0, n - i - 1):
            # Ascending order
            if not reverse and arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
            # Descending order
            elif reverse and arr[j] < arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]

    return arr


# Test
