```java
package com.example.ml;

import android.content.Context;
import android.graphics.Bitmap;
import org.tensorflow.lite.Interpreter;
import org.tensorflow.lite.Tensor;
import java.io.IOException;
import java.nio.ByteBuffer;
import java.nio.ByteOrder;

public class ImageClassifier {
    private final Interpreter interpreter;
    private final int inputSize = 224;
    private final float[][] outputProbabilities;

    public ImageClassifier(Context context, String modelPath) 
            throws IOException {
        ByteBuffer modelBuffer = loadModelFile(context, modelPath);
        interpreter = new Interpreter(modelBuffer);

        // Get output shape
        int[] outputShape = interpreter.getOutputTensor(0).shape();
        outputProbabilities = new float[1][outputShape[1]];
    }

    public ClassificationResult classify(Bitmap bitmap) {
        ByteBuffer input = preprocessImage(bitmap);
        interpreter.run(input, outputProbabilities);

        return postprocessResults();
    }

    private ByteBuffer preprocessImage(Bitmap bitmap) {
        ByteBuffer buffer = ByteBuffer.allocateDirect(
            4 * inputSize * inputSize * 3
        );
        buffer.order(ByteOrder.nativeOrder());

        // Resize and normalize
        Bitmap resized = Bitmap.createScaledBitmap(
            bitmap, inputSize, inputSize, true
        );

        int[] pixels = new int[inputSize * inputSize];
        resized.getPixels(pixels, 0, inputSize, 0, 0, 
                         inputSize, inputSize);

        for (int pixel : pixels) {
            // Normalize to [-1, 1]
            buffer.putFloat(((pixel >> 16) & 0xFF) / 127.5f - 1.0f);
            buffer.putFloat(((pixel >> 8) & 0xFF) / 127.5f - 1.0f);
            buffer.putFloat((pixel & 0xFF) / 127.5f - 1.0f);
        }

        buffer.rewind();
        return buffer;
    }

    private ClassificationResult postprocessResults() {
        float maxConfidence = 0;
        int maxIndex = 0;

        for (int i = 0; i < outputProbabilities[0].length; i++) {
            if (outputProbabilities[0][i] > maxConfidence) {
                maxConfidence = outputProbabilities[0][i];
                maxIndex = i;
            }
        }

        return new ClassificationResult(maxIndex, maxConfidence);
    }

    public void close() {
        interpreter.close();
    }
}
```

### PyTorch Mobile Implementation

```java
package com.example.ml;

import android.graphics.Bitmap;
import org.pytorch.IValue;
import org.pytorch.Module;
import org.pytorch.torchvision.TorchVision;
import java.io.IOException;

public class PyTorchClassifier {
    private Module module;

    public PyTorchClassifier(String modelPath) throws IOException {
        module = Module.load(modelPath);
    }

    public ClassificationResult classify(Bitmap bitmap) {
        // Convert to tensor
        long[] shape = {1, 3, 224, 224};
        float[] pixelValues = imageToFloatArray(bitmap);

        org.pytorch.Tensor inputTensor = 
            org.pytorch.Tensor.fromBlob(pixelValues, shape);

        // Run inference
        IValue outputs = module.forward(IValue.from(inputTensor));
        float[] scores = outputs.toTensor().getDataAsFloatArray();

        return getTopResult(scores);
    }

    private float[] imageToFloatArray(Bitmap bitmap) {
        float[] data = new float[1 * 3 * 224 * 224];
        int[] pixels = new int[224 * 224];

        Bitmap resized = Bitmap.createScaledBitmap(
            bitmap, 224, 224, true
        );
        resized.getPixels(pixels, 0, 224, 0, 0, 224, 224);

        int idx = 0;
        for (int pixel : pixels) {
            data[idx++] = ((pixel >> 16) & 0xFF) / 255.0f;
            data[idx++] = ((pixel >> 8) & 0xFF) / 255.0f;
            data[idx++] = (pixel & 0xFF) / 255.0f;
        }

        return data;
    }
}
```

