}

.about-content {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 3rem;
    align-items: center;
}

.about-text h3 {
    color: var(--primary-color);
    font-size: 1.8rem;
    margin-bottom: 1rem;
}

.about-text p {
    color: #555;
    margin-bottom: 1.5rem;
    line-height: 1.8;
}

.mission-points {
    display: flex;
    flex-direction: column;
    gap: 1rem;
}

.point {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.point i {
    color: var(--success-color);
    font-size: 1.3rem;
}

.about-image img {
    width: 100%;
    border-radius: var(--border-radius);
    box-shadow: 0 10px 30px rgba(0,0,0,0.2);
}

/* IMPACT SECTION */
.impact {
    background: linear-gradient(135deg, #f5f7fa, #c3cfe2);
    padding: 80px 20px;
}

.impact-stats {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 2rem;
}

.stat-card {
    background: white;
    padding: 2rem;
    border-radius: var(--border-radius);
    text-align: center;
    box-shadow: 0 5px 15px rgba(0,0,0,0.1);
    transition: var(--transition);
}

.stat-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 25px rgba(0,0,0,0.15);
}

.stat-card h3 {
    color: var(--primary-color);
    font-size: 2.5rem;
    margin-bottom: 0.5rem;
}

.stat-card p {
    color: #666;
    font-size: 1.1rem;
}

/* PROGRAMS SECTION */
.programs {
    padding: 80px 20px;
    background: white;
}

.program-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 2.5rem;
}

.program-card {
    background: white;
    padding: 2.5rem;
    border-radius: var(--border-radius);
    box-shadow: 0 5px 15px rgba(0,0,0,0.1);
    transition: var(--transition);
    border-top: 4px solid var(--primary-color);
}

.program-card:hover {
    transform: translateY(-8px);
    box-shadow: 0 15px 35px rgba(0,0,0,0.15);
}

.program-icon {
    font-size: 3rem;
    color: var(--primary-color);
    margin-bottom: 1rem;
}

.program-card h3 {
    color: var(--dark-color);
    margin-bottom: 1rem;
    font-size: 1.5rem;
}

.program-card p {
    color: #666;
    margin-bottom: 1.5rem;
    line-height: 1.8;
}

.learn-more {
    color: var(--secondary-color);
    text-decoration: none;
    font-weight: bold;
    transition: var(--transition);
}

.learn-more:hover {
    color: var(--primary-color);
}

/* TESTIMONIALS SECTION */
.testimonials {
    background: linear-gradient(135deg, #667eea, #764ba2);
    color: white;
    padding: 80px 20px;
}

.testimonials h2 {
    color: white;
}

.testimonial-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: 2rem;
}

.testimonial-card {
    background: rgba(255,255,255,0.1);
    padding: 2rem;
    border-radius: var(--border-radius);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255,255,255,0.2);
}

.testimonial-card p {
    margin-bottom: 1.5rem;
    line-height: 1.8;
    font-size: 0.95rem;
}

.testimonial-author {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.testimonial-author img {
    width: 50px;
    height: 50px;
    border-radius: 50%;
}

.testimonial-author h4 {
    margin-bottom: 0.3rem;
}

.testimonial-author p {
    margin: 0;
    font-size: 0.85rem;
    opacity: 0.9;
}

/* DONATION SECTION */
.donation-section {
    background: #f8f9fa;
    padding: 80px 20px;
    text-align: center;
}

.donation-section h2 {
    margin-bottom: 1rem;
}

.donation-section > .container > p {
    font-size: 1.1rem;
    color: #666;
    margin-bottom: 2.5rem;
}

.donation-options {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 2rem;
    margin-bottom: 2rem;
}

.donation-btn {
    background: white;
    border: 2px solid var(--primary-color);
    border-radius: var(--border-radius);
    padding: 2rem 1rem;
    cursor: pointer;
    transition: var(--transition);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
}

.donation-btn:hover {
    background: var(--primary-color);
    color: white;
    transform: scale(1.05);
}

.donation-btn .amount {
    font-size: 1.8rem;
    font-weight: bold;
}

.donation-btn .description {
    font-size: 0.85rem;
}

/* CONTACT SECTION */
.contact {
    padding: 80px 20px;
    background: white;
}

.contact-content {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 3rem;
}

.contact-info {
    display: flex;
    flex-direction: column;
    gap: 2rem;
}

.info-item {
    display: flex;
    gap: 1rem;
}

.info-item i {
    font-size: 1.5rem;
    color: var(--primary-color);
    margin-top: 0.25rem;
}

.info-item h4 {
    color: var(--dark-color);
    margin-bottom: 0.5rem;
}

.info-item p {
    color: #666;
}

.social-links {
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
}

.social-links a {
    width: 45px;
    height: 45px;
    background: var(--primary-color);
    color: white;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    text-decoration: none;
    transition: var(--transition);
    font-size: 1.2rem;
}

.social-links a:hover {
    background: var(--dark-color);
    transform: translateY(-3px);
}

.contact-form {
    display: flex;
    flex-direction: column;
    gap: 1rem;
}

.contact-form input,
.contact-form textarea {
    padding: 12px;
    border: 1px solid #ddd;
    border-radius: var(--border-radius);
    font-family: inherit;
    font-size: 1rem;
    transition: var(--transition);
}

.contact-form input:focus,
.contact-form textarea:focus {
    outline: none;
    border-color: var(--primary-color);
    box-shadow: 0 0 5px rgba(231, 76, 60, 0.3);
}

/* FOOTER */
.footer {
    background: linear-gradient(135deg, var(--dark-color), #34495e);
    color: white;
    padding: 3rem 20px 1rem;
}

.footer-content {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 2rem;
    margin-bottom: 2rem;
}

.footer-section h4 {
    margin-bottom: 1rem;
    color: var(--primary-color);
}

.footer-section ul {
    list-style: none;
}

.footer-section ul li {
    margin-bottom: 0.5rem;
}

.footer-section a {
    color: #bbb;
    text-decoration: none;
    transition: var(--transition);
}

.footer-section a:hover {
    color: var(--primary-color);
}

.footer-bottom {
    text-align: center;
    padding-top: 2rem;
    border-top: 1px solid rgba(255,255,255,0.1);
    color: #aaa;
}

.footer-bottom i {
    color: var(--primary-color);
}

/* RESPONSIVE DESIGN */
@media (max-width: 768px) {
    .nav-menu {
        flex-direction: column;
        gap: 1rem;
    }

    .hero-content h1 {
        font-size: 2rem;
    }

    .about-content,
    .contact-content {
        grid-template-columns: 1fr;
    }

    .impact-stats {
        grid-template-columns: repeat(2, 1fr);
    }

    .donation-options {
        grid-template-columns: repeat(2, 1fr);
    }

    .testimonial-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 480px) {
    .hero-content h1 {
        font-size: 1.5rem;
    }

    .impact-stats {
        grid-template-columns: 1fr;
    }

    .donation-options {
        grid-template-columns: 1fr;
    }

    .nav-menu {
        gap: 0.5rem;
        font-size: 0.9rem;
    }
}
```

## JavaScript Functionality

```javascript
// SMOOTH SCROLLING
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function (e) {
        e.preventDefault();
        const target = document.querySelector(this.getAttribute('href'));
        if (target) {
            target.scrollIntoView({ behavior: 'smooth' });
        }
    });
});

// DONATION BUTTON HANDLING
document.querySelectorAll('.donation-btn').forEach(btn => {
    btn.addEventListener('click', function() {
        const amount = this.querySelector('.amount').textContent;
        if (amount !== 'Custom') {
            alert(`Redirecting to payment for ${amount}`);
            // In production: window.location.href = paymentGateway;
        } else {
            const customAmount = prompt('Enter donation amount:');
            if (customAmount) {
                alert(`Redirecting to payment for $${customAmount}`);
            }
        }
    });
});

// CONTACT FORM HANDLING
const contactForm = document.querySelector('.contact-form');
if (contactForm) {
    contactForm.addEventListener('submit', function(e) {
        e.preventDefault();
        alert('Thank you for your message! We will get back to you soon.');
        this.reset();
    });
}

// CTA BUTTON HANDLING
document.querySelectorAll('.cta-button').forEach(btn => {
    btn.addEventListener('click', function() {
        const donateSection = document.getElementById('donate');
        if (donateSection) {
            donateSection.scrollIntoView({ behavior: 'smooth' });
        }
    });
});

// NAVBAR HIGHLIGHT ON SCROLL
window.addEventListener('scroll', () => {
    const sections = document.querySelectorAll('section');
    const navLinks = document.querySelectorAll('.nav-menu a');

    let current = '';
    sections.forEach(section => {
        const sectionTop = section.offsetTop;
        if (scrollY >= sectionTop - 200) {
            current = section.getAttribute('id');
        }
    });

    navLinks.forEach(link => {
        link.classList.remove('active');
        if (link.getAttribute('href').slice(1) === current) {
            link.classList.add('active');
        }
    });
});

// ANIMATION ON SCROLL
const observerOptions = {
    threshold: 0.1,
    rootMargin: '0px 0px -100px 0px'
};

const observer = new IntersectionObserver(function(entries) {
    entries.forEach(entry => {
        if (entry.isIntersecting) {
            entry.target.style.opacity = '1';
            entry.target.style.transform = 'translateY(0)';
        }
    });
}, observerOptions);

document.querySelectorAll('.program-card, .stat-card, .testimonial-card').forEach(el => {
    el.style.opacity = '0';
    el.style.transform = 'translateY(20px)';
    el.style.transition = 'all 0.6s ease';
    observer.observe(el);
});
```

## Key Features:

1. **Professional Navigation** - Sticky header with smooth scrolling
2. **Hero Section** - Eye-catching banner with CTA
3. **About Section** - Mission statement with key points
4. **Impact Metrics** - Statistics showcasing achievements
5. **Programs Overview** - Detailed program cards
6. **Testimonials** - Real stories from beneficiaries
7. **Donation Options** - Multiple giving levels
8. **Contact Section** - Multiple ways to reach out
9. **Responsive Design** - Works on all devices
10. **Interactive Elements** - Hover effects and animations

This design is modern, accessible, and focused on encouraging donations while building trust!
